code = """import json

# Load funding data for disaster projects
disaster_funding = var_functions.query_db:20

# Load civic documents with 2022 references
file_path = var_functions.query_db:24
with open(file_path, 'r') as f:
    civic_docs = json.load(f)

print('Funding records:', len(disaster_funding))
print('Civic docs:', len(civic_docs))

# Map project names to funding amounts
funding_map = {}
for record in disaster_funding:
    funding_map[record['Project_Name']] = int(record['Amount'])

# Find projects started in 2022
projects_2022 = []
total_funding = 0

for project_name in funding_map.keys():
    # Get the base project name (without FEMA/CalOES suffix)
    base_name = project_name.split(' (')[0]
    
    # Search documents for this project with 2022
    for doc in civic_docs:
        text = doc.get('text', '')
        
        if base_name in text and '2022' in text:
            # Count this as a 2022 project
            if project_name not in projects_2022:
                projects_2022.append(project_name)
                amount = funding_map[project_name]
                total_funding += amount
                print('Found:', project_name, amount)
            break

result = {
    'total_funding': total_funding,
    'project_count': len(projects_2022)
}

print('__RESULT__:')
print(json.dumps(result))"""

